#include <stdio.h>
#include <limits.h>

int findCityWithSmallestNeighbors(int totalCities, int roadConnections[][3], int numRoads, int maxDistance) {
    int dist[totalCities][totalCities];
    for (int i = 0; i < totalCities; i++) {
        for (int j = 0; j < totalCities; j++) {
            dist[i][j] = INT_MAX;
        }
        dist[i][i] = 0;
    }

    // Build graph
    for (int i = 0; i < numRoads; i++) {
        int u = roadConnections[i][0];
        int v = roadConnections[i][1];
        int w = roadConnections[i][2];
        dist[u][v] = w;
        dist[v][u] = w;
    }

    // Floyd–Warshall
    for (int k = 0; k < totalCities; k++) {
        for (int i = 0; i < totalCities; i++) {
            for (int j = 0; j < totalCities; j++) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
    }

    int minCnt = INT_MAX;
    int ans = -1;

    for (int i = 0; i < totalCities; i++) {
        int cnt = 0;
        for (int j = 0; j < totalCities; j++) {
            if (i != j && dist[i][j] <= maxDistance) {
                cnt++;
            }
        }

        if (cnt < minCnt || (cnt == minCnt && i > ans)) {
            minCnt = cnt;
            ans = i;
        }
    }

    return ans;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int totalCities;
        scanf("%d", &totalCities);
        int roadConnections[totalCities * (totalCities - 1) / 2][3];
        int numRoads = 0;
        for (int i = 0; i < totalCities; i++) {
            for (int j = i + 1; j < totalCities; j++) {
                int distance;
                scanf("%d", &distance);
                roadConnections[numRoads][0] = i;
                roadConnections[numRoads][1] = j;
                roadConnections[numRoads][2] = distance;
                numRoads++;
            }
        }
        int maxDistance;
        scanf("%d", &maxDistance);
        printf("%d\n", findCityWithSmallestNeighbors(totalCities, roadConnections, numRoads, maxDistance));
    }
    return 0;
}

